INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Hosted, customizable login$q$, $q$A fully branded, hosted login and signup experience supporting social login, passwordless, and MFA out of the box.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Enterprise SSO (SAML and OIDC)$q$, $q$Connects to identity providers like Okta, Azure AD, and Google Workspace for single sign-on.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$SCIM user provisioning$q$, $q$Automatically syncs users and groups from a customer's identity provider, keeping roles and directory data up to date.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Multi-tenancy and organization management$q$, $q$First-class support for isolating users, roles, and permissions per customer organization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Role-based access control$q$, $q$Fine-grained permissions and roles configurable per tenant or application.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Entitlements and subscription-aware permissions$q$, $q$Ties feature access directly to subscription plan tiers without a separate billing-to-permissions system.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Machine-to-machine authentication$q$, $q$API tokens and M2M authentication for service-to-service calls.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Frontegg Flows$q$, $q$AI-assisted tooling for generating multi-step authentication and onboarding workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Generous free tier (7,500 MAU) that includes real SSO and SCIM connections, unusual among CIAM vendors$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Purpose-built for B2B multi-tenancy rather than bolted on afterward$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Combines identity with entitlements and subscription logic, reducing the need for a separate feature-gating system$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Both hosted UI and headless API options give engineering teams flexibility$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Usage-based overage pricing beyond the free tier is not fully transparent on the public pricing page$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Enterprise tier requires a sales conversation, adding friction for teams wanting instant self-serve pricing$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Smaller company than Okta or Auth0, which may matter to security-conscious enterprise buyers evaluating vendor stability$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Migrating an existing large user base into Frontegg's tenant model can require nontrivial engineering work$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Is Frontegg free?$q$, $q$Yes, Frontegg's Pay-as-you-Go plan is free up to 7,500 monthly active users and includes hosted login, five enterprise SSO/SCIM connections, unlimited organizations, and a custom domain; usage beyond that is billed based on MAU and connection volume.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Does Frontegg support SAML and SCIM?$q$, $q$Yes, Frontegg supports both SAML and OpenID Connect for single sign-on and SCIM for automated user provisioning and deprovisioning from identity providers like Okta, Azure AD, and Google Workspace.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Who founded Frontegg?$q$, $q$Frontegg was founded in 2019 by Sagi Rodin and Aviad Mizrachi.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$How is Frontegg different from Auth0?$q$, $q$Frontegg is built specifically around B2B multi-tenancy, entitlements, and subscription-aware permissions, while Auth0 originated as a more general-purpose, consumer-oriented identity provider that typically requires more custom engineering to model multi-tenant B2B hierarchies.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Can Frontegg be self-hosted?$q$, $q$No, Frontegg is delivered as a hosted, managed CIAM service accessed through APIs and SDKs; teams that require full self-hosting typically consider alternatives like FusionAuth or Keycloak instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$What is Frontegg Flows?$q$, $q$Frontegg Flows is an AI-assisted feature that helps teams generate multi-step identity and onboarding workflows, such as sign-up, verification, and SSO setup sequences, without manually coding each step.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Adding enterprise SSO to a growing SaaS product$q$, $q$A B2B SaaS company preparing to sell to larger enterprise customers integrates Frontegg to quickly offer SAML/OIDC SSO and SCIM provisioning, satisfying security questionnaires without building an in-house identity team.$q$, $q$Mid-market SaaS engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Multi-tenant platform user management$q$, $q$A vertical SaaS platform serving many customer organizations uses Frontegg's tenant and organization model to isolate each customer's users, roles, and permissions while managing them from a single admin console.$q$, $q$Platform and marketplace SaaS builders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Plan-based feature gating$q$, $q$A subscription SaaS product ties its pricing tiers directly to Frontegg's entitlements module so that feature access automatically updates when a customer upgrades or downgrades their plan.$q$, $q$Product and growth teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Pay as You Go$q$, $q$Free to start, then usage-based$q$, $q$Monthly (usage-based)$q$, NULL, $q$["7,500 monthly active users included free","Fully customized hosted login","5 enterprise SSO/SCIM connections","Unlimited organizations","Custom domain","Usage-based charges beyond free thresholds for additional MAU, connections, and M2M tokens"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, NULL, $q$["Everything in Pay as You Go","Additional add-ons available","Multiple isolated environments","Advanced fraud protection","99.99% uptime SLA","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Frontegg is a customer identity and access management platform purpose-built for B2B SaaS applications, handling authentication, authorization, multi-tenancy, and user management through hosted APIs and embeddable UI components.$q$, $q$Founded in 2019 by Sagi Rodin and Aviad Mizrachi and headquartered in Ramat Gan, Israel, Frontegg has raised approximately 70 million dollars from investors including Insight Partners, Stripes, and Pitango.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Frontegg supports SAML and OIDC single sign-on, SCIM provisioning, fine-grained role-based access control, and a hosted, fully customizable login experience.$q$, $q$An Entitlements module ties subscription plans directly to the identity layer, and Frontegg Flows uses AI to help teams assemble multi-step identity and onboarding workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Frontegg's Pay-as-you-Go plan is free for up to 7,500 monthly active users with five enterprise SSO/SCIM connections included, after which usage-based charges apply.$q$, $q$An Enterprise tier adds advanced fraud protection, multiple environments, a 99.99 percent uptime SLA, and premium support, priced through a custom sales quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d5eaaad6-9ac2-4633-a29e-68531875f434', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Multi-source waterfall enrichment$q$, $q$Queries 15-plus data providers per contact to maximize verified email and phone find rates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Pay-only-for-results credit pricing$q$, $q$Credits are deducted only when a verified data point is actually found.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$LinkedIn Sales Navigator workflow$q$, $q$Supports CSV export and URL-based import of Sales Navigator lead lists for enrichment.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Native CRM and workflow integrations$q$, $q$Direct integrations with HubSpot, Clay, Google Sheets, and Make.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Zapier connectivity$q$, $q$Connects to more than 1,000 additional apps through Zapier.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Full REST API$q$, $q$Documented API for building custom enrichment workflows into internal tooling.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Company enrichment$q$, $q$Returns company industry, headcount, founding date, location, and description from a LinkedIn URL or company name.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Unlimited user seats$q$, $q$Every plan, including the free trial, includes unlimited team members at no added cost.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Pay only when a contact is actually found, reducing wasted spend versus flat-fee enrichment tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Unlimited seats included on every plan, unlike most per-user sales tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Aggregates many providers, which tends to improve email and phone find rates versus single-source tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Credits roll over rather than expiring immediately at the end of a billing cycle$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$No proprietary contact database of its own, meaning data quality ultimately depends on third-party providers it aggregates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$LinkedIn's 2024 crackdown on Sales Navigator browser extensions removed the most seamless enrichment workflow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Mobile phone number credits are relatively expensive at 10 credits per verified number$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$As a young, seed-stage company, long-term roadmap and stability are less proven than larger, well-capitalized competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$What is waterfall enrichment?$q$, $q$Waterfall enrichment is a method of finding contact data by querying multiple third-party providers in sequence or parallel for the same contact and returning the best verified result, which typically produces higher find rates than relying on a single data source.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$How much does FullEnrich cost?$q$, $q$FullEnrich starts with a free 50-credit trial, then paid plans begin at 29 dollars per month for 500 credits (Starter) and 55 dollars per month for 1,000 credits (Pro), with lower per-credit rates available on annual billing and custom Enterprise pricing for high-volume teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Do I pay for enrichment attempts that fail?$q$, $q$No, FullEnrich only deducts credits when it successfully finds and verifies a data point such as a work email, personal email, or mobile phone number.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Who founded FullEnrich?$q$, $q$FullEnrich was founded in 2023 by Paul Seloriot and Benjamin Douablin.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Does FullEnrich charge per user seat?$q$, $q$No, every FullEnrich plan, including the free trial, includes unlimited user seats, so teams share one credit pool instead of paying per person.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Can FullEnrich integrate with my CRM?$q$, $q$Yes, FullEnrich has native integrations with HubSpot, Clay, Google Sheets, and Make, plus access to over 1,000 additional apps through Zapier and a documented API for custom integrations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Outbound prospecting list enrichment$q$, $q$A sales development team exports a list of prospects from LinkedIn Sales Navigator and runs it through FullEnrich to fill in verified work emails and mobile numbers before loading it into their outreach sequencer.$q$, $q$B2B sales development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Agency client enrichment at scale$q$, $q$A lead generation agency uses FullEnrich's unlimited-seat pricing to let its entire team enrich contact lists for multiple clients without paying additional per-user licensing fees.$q$, $q$Lead generation and marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Recruiting sourcing$q$, $q$A technical recruiter enriches a shortlist of candidates sourced from LinkedIn with verified personal contact details to increase outreach response rates.$q$, $q$Recruiters and talent sourcers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Free Trial$q$, $q$Free$q$, $q$One-time$q$, NULL, $q$["50 free credits","No credit card required","Full access to waterfall enrichment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Starter$q$, $q$$29/month ($26/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["500 credits per month (6,000/year on annual billing)","Unlimited user seats","Credits roll over 3 months (monthly) or 12 months (annual)","Access to HubSpot, Clay, Google Sheets, and Make integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Pro$q$, $q$$55/month ($49/month billed annually)$q$, $q$Monthly or Annual$q$, NULL, $q$["1,000 credits per month (12,000/year on annual billing)","Unlimited user seats","Full API access","Extended credit rollover"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$Enterprise / Scale$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["High-volume credit packages","Dedicated support","Custom integrations","Volume discounts for agencies and large sales teams"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FullEnrich is a waterfall contact enrichment platform that queries more than 15 third-party data providers to find verified work emails, personal emails, and mobile phone numbers for B2B sales teams.$q$, $q$Founded in 2023 by Paul Seloriot and Benjamin Douablin, the Paris and San Francisco-based company raised a 2 million dollar seed round led by Flex Capital in February 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$FullEnrich only charges credits when a contact data point is actually found, and offers native integrations with HubSpot, Clay, Google Sheets, and Make, plus 1,000-plus apps via Zapier and a full API.$q$, $q$Every plan includes unlimited user seats, a departure from the per-seat pricing common among enrichment and CRM tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$FullEnrich starts with a free 50-credit trial, then Starter at 29 dollars per month for 500 credits and Pro at 55 dollars per month for 1,000 credits, both cheaper on annual billing.$q$, $q$Credits are charged only on success, at 1 credit per work email, 3 per personal email, and 10 per verified mobile phone number, and roll over rather than expiring immediately.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d4f6d848-146d-4c0c-baaf-da4e04d92eb6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Full session replay$q$, $q$Pixel and DOM-level fidelity recording of every user session.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Retroactively searchable session index$q$, $q$Search sessions for interactions that were never explicitly instrumented in advance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Frustration signal detection$q$, $q$Automatically flags rage clicks, dead clicks, and error clicks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Heatmaps and click maps$q$, $q$Visualizes where users click, scroll, and engage on a page.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Conversion funnel analysis$q$, $q$Tracks drop-off points across multi-step user flows.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$StoryAI session summaries$q$, $q$AI-generated plain-language summaries of what happened in a recorded session.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Native mobile SDKs$q$, $q$iOS and Android SDKs alongside the web JavaScript snippet.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Broad integration ecosystem$q$, $q$Connects with Segment, Amplitude, Google Analytics, Slack, Zendesk, Salesforce, and Jira.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Retroactive search lets teams investigate questions they did not think to track in advance$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Generous free plan (30,000 sessions/month) for evaluating the product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$StoryAI reduces manual time spent reviewing session recordings$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Deep integration ecosystem with existing analytics, support, and collaboration tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Session-based pricing can become expensive quickly for high-traffic sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Enterprise pricing is not published and requires a sales negotiation$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Recording and indexing every session raises privacy and PII-masking configuration overhead$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Less suited to teams wanting pure quantitative event analytics without session replay overhead$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Is FullStory free?$q$, $q$Yes, FullStory offers a free plan that includes 30,000 sessions per month, 12 months of data retention, and core session replay and analytics features for up to 10 users.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Who founded FullStory?$q$, $q$FullStory was founded in 2014 by Scott Voigt, Joel Webber, and Bruce Johnson in Atlanta, Georgia.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$How does FullStory pricing work?$q$, $q$FullStory prices its paid plans based on monthly session volume rather than per user seat, with published starting prices around 199 dollars per month for the Business tier and 499 dollars per month for the Advanced tier on annual billing, plus custom Enterprise contracts for larger organizations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$What is StoryAI?$q$, $q$StoryAI is FullStory's AI-powered feature that automatically analyzes recorded user sessions and generates plain-language summaries of what happened, helping teams identify issues without manually watching every recording.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$How is FullStory different from Hotjar?$q$, $q$FullStory emphasizes deep, fully indexed, retroactively searchable session data and AI-assisted analysis aimed at larger organizations, while Hotjar emphasizes simplicity and a broader set of lightweight feedback tools like heatmaps and surveys at a lower price point.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$What is FullStory's valuation and funding?$q$, $q$FullStory has raised approximately 196 million dollars from investors including Google Ventures, Permira, and Salesforce Ventures, reaching a valuation of 1.8 billion dollars.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Diagnosing checkout and conversion friction$q$, $q$An e-commerce product team uses FullStory's session replay and frustration signals to find where users abandon the checkout flow and prioritize fixes accordingly.$q$, $q$Product managers and UX researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Customer support ticket investigation$q$, $q$A customer support team pulls up the exact recorded session referenced in a bug report to see precisely what a user experienced, cutting down back-and-forth troubleshooting.$q$, $q$Customer support and success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Post-release regression detection$q$, $q$An engineering team searches sessions for spikes in error clicks or JavaScript errors immediately after a deploy to catch regressions before they generate widespread support tickets.$q$, $q$Front-end and QA engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["30,000 sessions per month","12 months data retention","Session replay","Basic analytics and debugging tools","Up to 10 users"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Business$q$, $q$From approximately $199/month$q$, $q$Annual (monthly available)$q$, NULL, $q$["Higher session volume than Free","Full session replay and search","Heatmaps and funnels","Standard integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Advanced$q$, $q$From approximately $499/month$q$, $q$Annual (monthly available)$q$, NULL, $q$["Everything in Business","StoryAI automated session summaries","Advanced analytics and segmentation","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Annual contract$q$, NULL, $q$["Everything in Advanced","Custom session volume","Dedicated account management","Advanced security and governance controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$FullStory is a digital experience intelligence platform that records and indexes every user session on a website or app so teams can retroactively search for interactions they never explicitly instrumented.$q$, $q$Founded in 2014 in Atlanta by Scott Voigt, Joel Webber, and Bruce Johnson, FullStory has raised roughly 196 million dollars and reached a 1.8 billion dollar valuation.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core capabilities include full session replay, heatmaps, conversion funnels, frustration signal detection, and StoryAI automated session summaries.$q$, $q$FullStory integrates with Segment, Amplitude, Google Analytics, Slack, Zendesk, Salesforce, and Jira, and offers native iOS and Android SDKs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Pricing is session-based: a free plan covers 30,000 sessions per month, Business starts around 199 dollars per month, and Advanced starts around 499 dollars per month on annual billing.$q$, $q$Enterprise pricing is custom and negotiated, with benchmark data suggesting average annual contracts around 30,000 dollars for SMBs and 80,000 dollars for enterprise customers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('21c299f2-5f17-4888-a6ff-d3d047043f79', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
